import React, { useState } from "react";
import { useFormik } from "formik";
import * as yup from "yup";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import axios from "../utils/axios";
import { base_url } from "../utils/axiosConfig";

const wibLogo = "/logo3.png";

// --- Helper Component for Styled Input Fields ---
// This makes our main form cleaner and re-usable
const InputField = ({ id, name, type, placeholder, icon, formik }) => (
  <div className="relative mb-6">
    <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
      {icon}
    </div>
    <input
      id={id}
      name={name}
      type={type}
      className={`form-input ${
        formik.touched[name] && formik.errors[name] ? "input-error" : ""
      }`}
      placeholder=" " // Important for floating label effect
      value={formik.values[name]}
      onChange={formik.handleChange}
      onBlur={formik.handleBlur}
    />
    <label htmlFor={id} className="form-label">
      {placeholder}
    </label>
    {formik.touched[name] && formik.errors[name] && (
      <p className="error-message">{formik.errors[name]}</p>
    )}
  </div>
);

// --- Yup Validation Schema (Unchanged) ---
const signUpSchema = yup.object({
  firstname: yup.string().required("First Name is Required"),
  lastname: yup.string().required("Last Name is Required"),
  email: yup
    .string()
    .required("Email is Required")
    .email("Email should be valid"),
  mobile: yup
    .string() // Changed to string to allow for international formats, validation can be more complex if needed
    .required("Mobile No is Required")
    .matches(/^[0-9]+$/, "Must be only digits")
    .min(10, "Must be at least 10 digits"),
  password: yup
    .string()
    .required("Password is Required")
    .min(8, "Password must be at least 8 characters"),
  confirmPassword: yup
    .string()
    .required("Confirm Password is Required")
    .oneOf([yup.ref("password"), null], "Passwords must match"),
});

// --- Main Signup Component ---
function Signup() {
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [loading, setLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);

  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      firstname: "",
      lastname: "",
      email: "",
      mobile: "",
      password: "",
      confirmPassword: "",
    },
    validationSchema: signUpSchema,
    onSubmit: async (values) => {
      setLoading(true);
      try {
        await axios.post(`${base_url}user/appRegister`, values);
        toast.success(
          "Registered! Please check your email to verify your account.",
        );
        setShowOtpInput(true); // Transition to OTP view
      } catch (error) {
        const errorMessage =
          error.response?.data?.message ||
          "An error occurred during registration.";
        toast.error(errorMessage);
      } finally {
        setLoading(false);
      }
    },
  });

  const verifyOtp = async () => {
    const otpCode = otp.join("");
    if (otpCode.length !== 6) {
      toast.error("Please enter a valid 6-digit OTP.");
      return;
    }
    setVerifyLoading(true);
    try {
      const email = formik.values.email;
      if (!email) {
        toast.error(
          "Email is missing. Please restart the registration process.",
        );
        setVerifyLoading(false);
        return;
      }

      await axios.post(`${base_url}user/verify-email`, { email, otp: otpCode });
      toast.success("Email verified successfully! You can now log in.");
      navigate("/login");
    } catch (error) {
      const errorMessage =
        error.response?.data?.message ||
        "An error occurred during OTP verification.";
      toast.error(errorMessage);
    } finally {
      setVerifyLoading(false);
    }
  };

  // Resend OTP functionality
  const handleResendOtp = async () => {
    if (loading) return;
    setLoading(true);
    try {
      // We can create a new endpoint for this or reuse the register endpoint logic
      // For simplicity, let's assume a resend endpoint exists.
      await axios.post(`${base_url}user/resend-verification-email`, {
        email: formik.values.email,
      });
      toast.success("A new OTP has been sent to your email.");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to resend OTP.");
    } finally {
      setLoading(false);
    }
  };

  // --- SVG Icons for Inputs ---
  const userIcon = (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      className="h-5 w-5 text-gray-400"
      viewBox="0 0 20 20"
      fill="currentColor"
    >
      <path
        fillRule="evenodd"
        d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z"
        clipRule="evenodd"
      />
    </svg>
  );
  const emailIcon = (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      className="h-5 w-5 text-gray-400"
      viewBox="0 0 20 20"
      fill="currentColor"
    >
      <path d="M2.003 5.884L10 9.882l7.997-3.998A2 2 0 0016 4H4a2 2 0 00-1.997 1.884z" />
      <path d="M18 8.118l-8 4-8-4V14a2 2 0 002 2h12a2 2 0 002-2V8.118z" />
    </svg>
  );
  const mobileIcon = (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      className="h-5 w-5 text-gray-400"
      viewBox="0 0 20 20"
      fill="currentColor"
    >
      <path d="M2 3a1 1 0 011-1h2.153a1 1 0 01.986.836l.74 4.435a1 1 0 01-.54 1.06l-1.518.759a11.03 11.03 0 004.28 4.28l.759-1.518a1 1 0 011.06-.54l4.435.74a1 1 0 01.836.986V17a1 1 0 01-1 1h-2C6.477 18 2 13.523 2 8V5a1 1 0 011-1h1z" />
    </svg>
  );
  const passwordIcon = (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      className="h-5 w-5 text-gray-400"
      viewBox="0 0 20 20"
      fill="currentColor"
    >
      <path
        fillRule="evenodd"
        d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z"
        clipRule="evenodd"
      />
    </svg>
  );

  const LoaderSpinner = () => (
    <svg
      className="animate-spin -ml-1 mr-3 h-5 w-5 text-white"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      ></circle>
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      ></path>
    </svg>
  );

  return (
    <>
      <main
        className="min-h-screen overflow-hidden py-10"
        style={{
          background: "linear-gradient(135deg, #14b8a6 0%, #0d9488 100%)",
        }}
      >
        <div className="signup-page-container ">
          <div className="signup-panel shadow-none">
            {/* --- Left Side: Branding --- */}
            <div
              className="branding-section"
              style={{
                background: "linear-gradient(135deg, #0d9488 0%, #0f766e 100%)",
              }}
            >
              <div className="branding-content">
                <div className="bg-white/10 backdrop-blur-md rounded-full p-6 inline-block mb-6 border border-white/20">
                  <svg
                    className="w-20 h-20 text-white"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth="1.5"
                      d="M19.423 15.423a2 2 0 00-2.828 0L12 20.018l-4.595-4.595a2 2 0 00-2.828 0L1 18.341l8.172 1.362a4 4 0 005.656 0L23 18.341l-3.577-2.918z"
                    />
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth="1.5"
                      d="M12 2v2m0 16v2m10-10h-2M4 10H2m15.364-5.364l-1.414 1.414M7.05 16.95l-1.414 1.414M16.95 16.95l1.414 1.414M7.05 7.05L5.636 5.636"
                    />
                  </svg>
                </div>
                <h1 className="text-3xl font-extrabold text-white mb-4 tracking-tight">
                  <Link
                    to="/"
                    className="hover:text-teal-200 transition-colors"
                  >
                    Join Pulse Addis
                  </Link>
                </h1>
                <p className="text-teal-50/90 text-lg font-medium leading-relaxed">
                  Your trusted partner in health. Get access to essential
                  medications and professional care today.
                </p>
                <div className="mt-8 pt-8 border-t border-white/10">
                  <p className="text-sm font-bold text-teal-200 uppercase tracking-widest">
                    Licensed Store
                  </p>
                </div>
              </div>
            </div>

            {/* --- Right Side: Form --- */}
            <div className="form-section ">
              <div className="">
                {/* Conditional Rendering: Show Register Form or OTP Form */}
                {!showOtpInput ? (
                  <div className="form-wrapper" key="register-form">
                    <div className="text-center mb-8">
                      <h2 className="text-3xl font-extrabold text-[#0d9488]">
                        Create Account
                      </h2>
                      <p className="text-gray-500 mt-2 font-medium">
                        Already have a health profile?{" "}
                        <Link
                          to="/login"
                          className="font-bold text-[#0d9488] hover:underline"
                        >
                          Log in here
                        </Link>
                      </p>
                    </div>

                    <form onSubmit={formik.handleSubmit} noValidate>
                      <div className="grid grid-cols-1 md:grid-cols-2 md:gap-x-6">
                        <InputField
                          id="firstname"
                          name="firstname"
                          type="text"
                          placeholder="First Name"
                          icon={userIcon}
                          formik={formik}
                        />
                        <InputField
                          id="lastname"
                          name="lastname"
                          type="text"
                          placeholder="Last Name"
                          icon={userIcon}
                          formik={formik}
                        />
                      </div>
                      <InputField
                        id="email"
                        name="email"
                        type="email"
                        placeholder="Email Address"
                        icon={emailIcon}
                        formik={formik}
                      />
                      <InputField
                        id="mobile"
                        name="mobile"
                        type="tel"
                        placeholder="Mobile Number"
                        icon={mobileIcon}
                        formik={formik}
                      />
                      <InputField
                        id="password"
                        name="password"
                        type="password"
                        placeholder="Password"
                        icon={passwordIcon}
                        formik={formik}
                      />
                      <InputField
                        id="confirmPassword"
                        name="confirmPassword"
                        type="password"
                        placeholder="Confirm Password"
                        icon={passwordIcon}
                        formik={formik}
                      />

                      <div>
                        <button
                          type="submit"
                          disabled={loading}
                          className="bg-gradient-to-r from-[#14b8a6] to-[#0d9488] px-5 py-3 text-white w-full rounded-xl font-bold text-lg shadow-lg hover:shadow-teal-200 hover:scale-[1.01] transition-all flex justify-center items-center gap-3"
                        >
                          {loading && <LoaderSpinner />}
                          {loading ? "Registering..." : "Join Pulse Addis"}
                        </button>
                      </div>
                    </form>
                  </div>
                ) : (
                  <div className="form-wrapper" key="otp-form">
                    <div className="text-center mb-8">
                      <svg
                        className="mx-auto h-12 w-12 text-green-500"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                        xmlns="http://www.w3.org/2000/svg"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth="2"
                          d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"
                        ></path>
                      </svg>
                      <h2 className="text-3xl font-bold text-gray-800 mt-4">
                        Verify Your Email
                      </h2>
                      <p className="text-gray-500 mt-2">
                        We've sent a 6-digit code to{" "}
                        <strong className="text-gray-700">
                          {formik.values.email}
                        </strong>
                        . Please enter it below to complete your registration.
                      </p>
                    </div>

                    <div className="flex flex-col items-center">
                      <label
                        htmlFor="otp"
                        className="block text-sm font-bold text-teal-800 text-center mb-6 uppercase tracking-widest"
                      >
                        Verification Code
                      </label>
                      <div className="flex gap-3 mb-2">
                        {otp.map((digit, index) => (
                          <input
                            key={index}
                            type="text"
                            maxLength="1"
                            value={digit}
                            onChange={(e) => {
                              const value = e.target.value.replace(
                                /[^0-9]/g,
                                "",
                              );
                              const newOtp = [...otp];
                              newOtp[index] = value;
                              setOtp(newOtp);
                              if (value && index < 5) {
                                document
                                  .getElementById(`otp-${index + 1}`)
                                  .focus();
                              }
                            }}
                            onKeyDown={(e) => {
                              if (
                                e.key === "Backspace" &&
                                !otp[index] &&
                                index > 0
                              ) {
                                document
                                  .getElementById(`otp-${index - 1}`)
                                  .focus();
                              }
                            }}
                            id={`otp-${index}`}
                            className="w-12 h-14 text-center text-2xl font-bold rounded-xl border-2 border-teal-100 bg-teal-50/50 focus:border-teal-500 focus:bg-white focus:ring-4 focus:ring-teal-100 transition-all outline-none"
                          />
                        ))}
                      </div>
                      <p className="text-xs text-center text-red-500 mt-2 h-4 font-medium">
                        {otp.join("").length > 0 && otp.join("").length < 6
                          ? "Code must be 6 digits"
                          : ""}
                      </p>
                    </div>

                    <div className="mt-6">
                      <button
                        onClick={verifyOtp}
                        disabled={verifyLoading}
                        className="text-white px-5 py-2 sm:w-full bg-[#ff0000]"
                      >
                        {verifyLoading && <LoaderSpinner />}
                        {verifyLoading
                          ? "Verifying..."
                          : "Verify & Create Account"}
                      </button>
                    </div>
                    {/*
                    <div className="text-center mt-6 text-sm text-gray-500">
                      <p>Didn't receive the code?</p>
                      <button onClick={handleResendOtp} disabled={loading} className="font-medium text-indigo-600 hover:text-indigo-500 disabled:opacity-50">
                        {loading ? 'Sending...' : 'Resend Code'}
                      </button>
                    </div>
                    */}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>

      <style jsx global>{`
        :root {
          --primary-color: #0d9488; /* teal-600 */
          --primary-color-hover: #0f766e; /* teal-700 */
          --input-border-color: #e5e7eb; /* gray-200 */
          --input-focus-border-color: #0d9488; /* teal-600 */
          --error-color: #ef4444; /* red-500 */
          --form-bg-color: #ffffff;
          --page-bg-color: #f9fafb; /* gray-50 */
        }

        .signup-page-container {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 2rem 1rem;
          background: linear-gradient(135deg, #14b8a6 0%, #0d9488 100%);
        }

        .signup-panel {
          width: 100%;
          max-width: 64rem;
          background-color: var(--form-bg-color);
          border-radius: 0.75rem;
          box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
          display: flex;
          overflow: hidden;
          margin-top: -6rem; /* Adjust if needed based on breadcrumb height */
        }

        .branding-section {
          display: none;
        }
        @media (min-width: 768px) {
          .branding-section {
            display: flex;
            align-items: center;
            justify-content: center;
            width: 45%;
            background: linear-gradient(
              135deg,
              #ff7e5f,
              #feb47b
            ); /* Example: A warm, inviting gradient */
            padding: 2.5rem;
          }
        }

        .branding-content {
          text-align: center;
          color: white;
        }

        .form-section {
          width: 100%;
          padding: 2rem;
        }
        @media (min-width: 768px) {
          .form-section {
            width: 55%;
            padding: 3rem;
          }
        }

        .form-wrapper {
          animation: fadeIn 0.5s ease-in-out;
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .form-input {
          display: block;
          width: 100%;
          padding: 0.75rem 0.75rem 0.75rem 2.5rem;
          font-size: 1rem;
          color: #111827;
          background-color: #f9fafb; /* Slightly off-white */
          border: 1px solid var(--input-border-color);
          border-radius: 0.5rem; /* Slightly more rounded */
          transition: all 0.2s ease-in-out;
        }

        .form-input:focus {
          color: #111827;
          background-color: #fff;
          border-color: var(--input-focus-border-color);
          outline: 0;
          box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.1);
        }

        .form-input::placeholder {
          color: transparent;
        }

        .form-label {
          position: absolute;
          top: 0.75rem;
          left: 2.5rem;
          font-size: 1rem;
          color: #6b7280;
          pointer-events: none;
          transition: all 0.2s ease-out;
        }

        .form-input:focus ~ .form-label,
        .form-input:not(:placeholder-shown) ~ .form-label {
          top: -0.65rem;
          left: 2rem;
          font-size: 0.75rem;
          color: var(--primary-color);
          background-color: var(--form-bg-color);
          padding: 0 0.25rem;
        }

        .input-error {
          border-color: var(--error-color) !important;
        }
        .input-error:focus {
          box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.1) !important;
        }
        .error-message {
          color: var(--error-color);
          font-size: 0.875rem;
          margin-top: 0.25rem;
        }

        .submit-button {
          display: inline-flex;
          align-items: center;
          justify-content: center;
          width: 100%;
          padding: 0.875rem 1rem; /* Slightly taller button */
          background-color: var(--primary-color);
          color: white;
          font-weight: 600;
          font-size: 1rem;
          border-radius: 0.5rem;
          border: none;
          cursor: pointer;
          transition:
            background-color 0.2s,
            transform 0.1s;
        }
        .submit-button:hover:not(:disabled) {
          background-color: var(--primary-color-hover);
          transform: translateY(-2px);
        }
        .submit-button:disabled {
          opacity: 0.6;
          cursor: not-allowed;
        }

        .otp-input-container {
          display: flex;
          justify-content: center;
          gap: 0.5rem;
        }
        .otp-input {
          width: 3rem;
          height: 3.5rem;
          text-align: center;
          font-size: 1.5rem;
          font-weight: 600;
          border: 1px solid var(--input-border-color);
          border-radius: 0.5rem;
          transition: all 0.2s ease;
        }
        .otp-input:focus {
          border-color: var(--primary-color);
          outline: none;
          box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.1);
        }
      `}</style>
    </>
  );
}

export default Signup;
